sql:
SELECT substance_name, molecular_weight
FROM substances
WHERE molecular_weight = (SELECT MIN(molecular_weight) FROM substances);

SELECT status_description
FROM compatibility_status
WHERE status_code = 'C';

SELECT COUNT(study_id) 
FROM compatibility_studies 
WHERE study_location = 'Tokyo, Japan';

SELECT study_title
FROM compatibility_studies
WHERE study_date = '2023-01-01';

external_knowledge:
- 'do not mix well' refers to substances that are incompatible with the drug;
- 'oil and water' is a metaphor for substances that do not mix or are incompatible;
- 'concentration_type' represents the unit of measurement for the concentration of the substance, such as mg/mL or mcg/mL.

sql:
SELECT COUNT(status_id) AS compatible_count
FROM compatibility_status
WHERE status_code = 'C';

SELECT substance_name 
FROM substances 
WHERE substance_id = 1;

SELECT status_code 
FROM compatibility_status 
WHERE status_id = 1;

SELECT AVG(molecular_weight) AS average_molecular_weight
FROM substances
WHERE concentration_type = 'mg/mL';
